import React, { useState, useEffect } from 'react';
import { replicateAesthetic } from '../services/geminiService';
import { batchGenerateTracks } from '../services/musicService';
import { generateLofiBackground } from '../services/videoService';
import { saveTrack, saveMix } from '../lib/storage';
import { Mood, MusicProvider, Mix, ExportData, Track, VisualTheme } from '../types';
import { INITIAL_USER } from '../constants';
import { 
  Zap, 
  Loader2, 
  CheckCircle2, 
  Play, 
  Youtube, 
  Layers, 
  Sparkles, 
  Monitor, 
  Music, 
  ChevronRight,
  AlertCircle
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const CHANNEL_blueprints = [
  { category: 'Study', mood: Mood.FOCUS, title: 'The Modern Scholar', tracks: 4 },
  { category: 'Night', mood: Mood.NIGHT, title: 'Neon Pulse Synthwave', tracks: 4 },
  { category: 'Sleep', mood: Mood.SLEEP, title: 'Midnight Dreamer', tracks: 4 },
];

export const ChannelCloner: React.FC = () => {
  const navigate = useNavigate();
  const [isProducing, setIsProducing] = useState(false);
  const [activeStep, setActiveStep] = useState<number | null>(null);
  const [completedJobs, setCompletedJobs] = useState<string[]>([]);
  const [statusText, setStatusText] = useState("Ready to spawn channel assets...");

  const processProduction = async () => {
    setIsProducing(true);
    setCompletedJobs([]);

    try {
      for (let i = 0; i < CHANNEL_blueprints.length; i++) {
        const blueprint = CHANNEL_blueprints[i];
        setActiveStep(i);
        setStatusText(`Analyzing DNA for ${blueprint.category}...`);

        // 1. Replicate Aesthetic DNA
        const aestheticData = await replicateAesthetic(blueprint.category);

        // 2. Generate Improved Audio Assets
        setStatusText(`Generating improved audio for ${blueprint.title}...`);
        const tracks = await batchGenerateTracks(blueprint.tracks, {
          mood: aestheticData.mood,
          provider: MusicProvider.BEATOVEN,
          bpmMin: aestheticData.bpmRange.min,
          bpmMax: aestheticData.bpmRange.max,
          durationSeconds: aestheticData.suggestedDuration,
          titleBase: blueprint.title
        });
        tracks.forEach(saveTrack);

        // 3. Generate Visual Loop
        setStatusText(`Rendering 2D visual loop for ${blueprint.title}...`);
        // Fix: Explicitly pass VisualTheme and mood string to match generateLofiBackground signature and resolve type error
        const videoUrl = await generateLofiBackground(
          `Anime character in a ${blueprint.category.toLowerCase()} setting, improved fidelity, ${aestheticData.reasoning}`, 
          VisualTheme.CLASSIC_ANIME,
          aestheticData.mood.toLowerCase()
        );

        // 4. Finalize Production Bundle
        setStatusText(`Packaging production bundle...`);
        const totalDuration = tracks.reduce((acc, t) => acc + t.durationSeconds, 0);
        let currentStartTime = 0;
        const timestamps = tracks.map(t => {
          const m = Math.floor(currentStartTime / 60);
          const s = currentStartTime % 60;
          const stamp = `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
          currentStartTime += t.durationSeconds - 5; // 5s crossfade
          return `${stamp} ${t.title}`;
        }).join('\n');

        const bundle: ExportData = {
          timestampList: timestamps,
          youtubeDescription: `✨ ${blueprint.title} - Improved Volume ✨\n\nTracklist:\n${timestamps}\n\nStyle: ${aestheticData.reasoning}\nImprovements: ${aestheticData.improvementSuggestions.join(', ')}`,
          m3uContent: "",
          jsonConfig: "",
          titleSuggestion: `lofi hip hop radio - beats to ${blueprint.category.toLowerCase()} [Improved Edition]`,
          thumbnailPrompt: blueprint.category
        };

        const newMix: Mix = {
          id: `spawn_${Date.now()}_${i}`,
          userId: INITIAL_USER.id,
          name: blueprint.title,
          mood: aestheticData.mood,
          totalDurationSeconds: totalDuration,
          crossfadeDuration: 5,
          trackIds: tracks.map(t => t.id),
          videoUrl: videoUrl,
          exportData: bundle,
          createdAt: new Date().toISOString(),
          isPublished: false
        };

        saveMix(newMix);
        setCompletedJobs(prev => [...prev, blueprint.category]);
      }

      setStatusText("Channel Spawning Complete! Redircting to Command Center...");
      setTimeout(() => navigate('/'), 2000);
    } catch (err) {
      console.error(err);
      setStatusText("Production interrupted. Check API console.");
    } finally {
      setIsProducing(false);
      setActiveStep(null);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700 pb-20">
      <header className="text-center space-y-4">
        <div className="inline-flex items-center space-x-2 px-4 py-2 bg-amber-500/10 text-amber-500 rounded-full border border-amber-500/20 mb-4">
          <Zap size={14} className="animate-pulse" />
          <span className="text-[10px] font-black uppercase tracking-widest">Advanced Orchestrator</span>
        </div>
        <h1 className="text-5xl font-black text-white tracking-tight">Channel Spawn Engine</h1>
        <p className="text-slate-400 text-lg max-w-xl mx-auto">
          Automatically clone and improve the entire Lo-Fi Girl ecosystem in one click. Generates 3 full volumes with video and metadata.
        </p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {CHANNEL_blueprints.map((bp, i) => (
          <div 
            key={bp.category}
            className={`p-6 rounded-[2.5rem] border transition-all duration-500 flex flex-col items-center text-center space-y-4 ${
              activeStep === i 
                ? 'bg-amber-500/10 border-amber-500 shadow-2xl shadow-amber-500/10 scale-105 z-10' 
                : completedJobs.includes(bp.category)
                  ? 'bg-slate-900 border-emerald-500/30'
                  : 'bg-slate-900/40 border-slate-800 opacity-60'
            }`}
          >
            <div className={`w-16 h-16 rounded-2xl flex items-center justify-center ${
              activeStep === i ? 'bg-amber-500 text-slate-950 animate-bounce' : 'bg-slate-800 text-slate-500'
            }`}>
               {bp.category === 'Study' && <Monitor size={28} />}
               {bp.category === 'Night' && <Sparkles size={28} />}
               {bp.category === 'Sleep' && <Music size={28} />}
            </div>
            <div>
              <h3 className="font-bold text-white">{bp.title}</h3>
              <p className="text-[10px] text-slate-500 uppercase tracking-widest mt-1">Status: {
                completedJobs.includes(bp.category) ? 'Bundled' : (activeStep === i ? 'Processing' : 'Queued')
              }</p>
            </div>
            {completedJobs.includes(bp.category) && <CheckCircle2 className="text-emerald-500" size={24} />}
          </div>
        ))}
      </div>

      <div className="bg-slate-900/60 border border-slate-800 rounded-[3rem] p-10 flex flex-col items-center space-y-8 shadow-2xl">
        <div className="flex flex-col items-center space-y-3">
          {isProducing ? (
            <div className="relative">
              <Loader2 className="w-20 h-20 text-amber-500 animate-spin" />
              <div className="absolute inset-0 flex items-center justify-center">
                <Youtube size={24} className="text-rose-500" />
              </div>
            </div>
          ) : (
            <div className="p-8 bg-slate-950 rounded-full border border-slate-800">
               <Zap className="w-12 h-12 text-amber-500" />
            </div>
          )}
          <div className="text-center">
            <h4 className="text-xl font-bold text-white">{isProducing ? "Executing Production Pipeline" : "Spawn Full Channel"}</h4>
            <p className="text-slate-500 text-sm mt-1">{statusText}</p>
          </div>
        </div>

        {!isProducing && (
          <button 
            onClick={processProduction}
            className="group px-12 py-5 bg-amber-500 hover:bg-amber-400 text-slate-950 rounded-[2rem] font-black text-lg shadow-2xl shadow-amber-500/20 transition-all hover:scale-[1.05] active:scale-95 flex items-center space-x-3"
          >
            <span>Start Automated Production</span>
            <ChevronRight size={24} className="group-hover:translate-x-1 transition-transform" />
          </button>
        )}

        <div className="flex items-start space-x-3 max-w-lg p-5 bg-slate-950/50 rounded-3xl border border-slate-800">
           <AlertCircle className="text-blue-400 shrink-0" size={18} />
           <p className="text-[11px] text-slate-500 leading-relaxed italic">
             This process will generate approximately 12 tracks and 3 HD video loops. Ensure your Gemini API key is valid and you have a stable connection. Generation can take several minutes per volume.
           </p>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
