        </div>

        <div className="lg:col-span-5 grid grid-cols-1 gap-4">
           {/* Visual Style Architect */}
           <div className="bg-slate-900/40 border border-slate-800 rounded-[2rem] p-6 space-y-4 shadow-xl flex flex-col">
