        </div>
        <h1 className="text-5xl font-black text-white tracking-tight">Production Factory</h1>
        <p className="text-slate-400 text-lg max-w-2xl mx-auto leading-relaxed">
          Clone and evolve the Lo-Fi aesthetic into high-fidelity broadcast assets. Multi-volume batching engine.
        </p>
      </header>

      {/* Global Progress Header */}
      {isProducing && (
