                <div className={`flex items-center justify-between text-xs ${isActive && subStep === 'audio' ? 'text-amber-500' : isDone || (isActive && ['visual', 'packaging'].includes(subStep)) ? 'text-emerald-500' : 'text-slate-600'}`}>
