          trackIds: tracks.map(t => t.id),
          videoUrl: videoUrl,
          exportData: bundle,
          createdAt: new Date().toISOString(),
          isPublished: false
        };

        saveMix(newMix);
        setCompletedVolumes(prev => [...prev, newMix]);
        addLog(`[READY] '${blueprint.title}' bundle saved to vault.`);
